import java.util.ArrayList;import java.util.List;import java.util.Map;
final class ProxyPattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String c){super(c);code=c;}String code(){return code;}}
  interface Subject{String read(String name);}
  static final class DocumentStore implements Subject{private final Map<String,String>documents=Map.of("public","status:ok","secret","key:rotated");public String read(String name){String value=documents.get(name);if(value==null)throw new PatternException("not_found");return value;}}
  static final class DocumentProxy implements Subject{private final String role;private Subject subject;private int loadCount;DocumentProxy(String role){this.role=role;}public String read(String name){if(name.equals("secret")&&!role.equals("admin"))throw new PatternException("forbidden");if(subject==null){subject=new DocumentStore();loadCount++;}return subject.read(name);}int loadCount(){return loadCount;}}
  @SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){DocumentProxy proxy=new DocumentProxy(String.valueOf(input.getOrDefault("role","viewer")));List<String>values=new ArrayList<>();for(Object name:(List<Object>)input.getOrDefault("reads",List.of()))values.add(proxy.read(String.valueOf(name)));return Map.of("values",values,"load_count",proxy.loadCount());}}
